	@Test
	public void repeatedStoreCloseReturnsGlobalBudgetToBaseline() {
		long baseline = LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get();
		for (int iteration = 0; iteration < 3; iteration++) {
			rows(chain());
			assertThat(LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get()).isGreaterThan(baseline);

			repository.shutDown();
			repository = null;
			assertThat(LmdbCsrAdjacencyCache.GLOBAL_USED_BYTES.get())
					.as("closed store %s must return its complete CSR charge", iteration)
					.isEqualTo(baseline);

			if (iteration < 2) {
				repository = openRepository(new File(dataDir, "close-" + iteration));
			}
		}
	}

